const { Storage } = require('@google-cloud/storage');
const storage = new Storage();

exports.serveFile = async (req, res) => {
  const { bucket, filePath } = req.query;

  // Validate that bucket and filePath parameters are provided
  if (!bucket || !filePath) {
    res.status(400).send('Missing "bucket" or "filePath" query parameter.');
    return;
  }

  const file = storage.bucket(bucket).file(filePath);

  try {
    // Check if the file exists
    const [exists] = await file.exists();
    if (!exists) {
      res.status(404).send('File not found.');
      return;
    }

    // Get file metadata to determine Content-Type
    const [metadata] = await file.getMetadata();
    const contentType = metadata.contentType || 'application/octet-stream';

    // Set appropriate response headers
    res.set('Content-Type', contentType);
    res.set('Cache-Control', 'public, max-age=3600, no-transform'); // Example caching header

    // Create a readable stream from the Cloud Storage file
    const readStream = file.createReadStream();

    // Handle errors during streaming from Cloud Storage
    readStream.on('error', (err) => {
      console.error(`Error reading file "${filePath}" from bucket "${bucket}":`, err);
      if (!res.headersSent) {
        res.status(500).send('Error streaming file.');
      } else {
        // If headers already sent, client might get incomplete data.
        // End the response to prevent hanging.
        res.end();
      }
    });

    // Pipe the file stream directly to the HTTP response
    readStream.pipe(res);

    // Handle client disconnects or errors on the response stream
    res.on('error', (err) => {
      console.warn('Response stream error (client might have disconnected):', err.message);
      // Destroy the read stream to stop consuming Cloud Storage data
      readStream.destroy();
    });

  } catch (error) {
    console.error(`Unhandled error serving file "${filePath}" from bucket "${bucket}":`, error);

    // Provide more specific error responses if possible
    if (error.code === 403) { // Forbidden / Permission Denied
      res.status(403).send('Permission denied to access the specified bucket or file.');
    } else if (error.code === 400 || error.code === 404) { // Bad Request or Not Found
      // This is generally caught by file.exists() above, but good to have as fallback
      res.status(error.code).send(error.message);
    } else {
      res.status(500).send('Internal server error.');
    }
  }
};